from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    meta_path = Path(index_path) / f"{index_path}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError(f"Leann metadata file not found at {meta_path}")

    with open(meta_path, 'r') as f:
        meta_data = json.load(f)

    total_passages = meta_data.get('total_count', 0)

    # Assuming we can get the passage file path from the meta data
    passage_file_base = meta_data.get('passage_sources', [{}])[0].get('path')
    if not passage_file_base:
        return {
            "total_passages": total_passages,
            "metadata_fields": [],
            "field_value_counts": {}
        }

    passage_file = Path(index_path) / passage_file_base
    if not passage_file.exists():
        # If passage file is missing, we can't get field counts
        return {
            "total_passages": total_passages,
            "metadata_fields": [],
            "field_value_counts": {}
        }

    # Use PassageManager to read the passage file
    passage_manager = PassageManager()
    passage_dict = passage_manager.load_passage_file(str(passage_file))

    # Collect all fields from all passages
    all_fields = set()
    field_values = defaultdict(Counter)

    for passage_id, passage_data in passage_dict.items():
        if 'metadata' in passage_data:
            for field_name, value in passage_data['metadata'].items():
                all_fields.add(field_name)
                field_values[field_name][value] += 1

    return {
        "total_passages": total_passages,
        "metadata_fields": list(all_fields),
        "field_value_counts": {k: dict(v) for k, v in field_values.items()}
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    meta_path = Path(index_path) / f"{index_path}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError(f"Leann metadata file not found at {meta_path}")

    with open(meta_path, 'r') as f:
        meta_data = json.load(f)

    total_passages = meta_data.get('total_count', 0)
    if total_passages == 0:
        return {
            "coverage_percentage": 100.0,
            "field_coverage": {field: 100.0 for field in required_fields},
            "missing_fields": []
        }

    passage_file_base = meta_data.get('passage_sources', [{}])[0].get('path')
    if not passage_file_base:
        return {
            "coverage_percentage": 0.0,
            "field_coverage": {field: 0.0 for field in required_fields},
            "missing_fields": required_fields.copy()
        }

    passage_file = Path(index_path) / passage_file_base
    if not passage_file.exists():
        return {
            "coverage_percentage": 0.0,
            "field_coverage": {field: 0.0 for field in required_fields},
            "missing_fields": required_fields.copy()
        }

    passage_manager = PassageManager()
    passage_dict = passage_manager.load_passage_file(str(passage_file))

    covered_passages = 0
    field_coverages = {field: 0 for field in required_fields}
    missing_fields_in_passages = set(required_fields)

    for passage_data in passage_dict.values():
        if 'metadata' in passage_data:
            has_all_fields = True
            for field in required_fields:
                if field in passage_data['metadata']:
                    field_coverages[field] += 1
                    missing_fields_in_passages.discard(field)
                else:
                    has_all_fields = False
            if has_all_fields:
                covered_passages += 1

    coverage_percentage = (covered_passages / total_passages) * 100 if total_passages > 0 else 0.0
    field_coverage_percentages = {field: (count / total_passages) * 100 for field, count in field_coverages.items()}

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage_percentages,
        "missing_fields": list(missing_fields_in_passages)
    }
